function solve(nums) {
    const N = nums.length;

    // 1. Calculate sorted_nums
    const sorted_nums = [...nums].sort((a, b) => a - b);

    // 2. Find divisors D of N
    const divisors = [];
    for (let k = 1; k * k <= N; k++) {
        if (N % k === 0) {
            divisors.push(k);
            if (k * k !== N) {
                divisors.push(N / k);
            }
        }
    }

    let totalSum = 0;

    // 3. Check each divisor k
    for (const k of divisors) {
        let isSortable = true;

        if (k === 1) {
            // If k=1, the operation is null. Sorting is only possible if nums is already sorted.
            if (nums.join(',') !== sorted_nums.join(',')) {
                isSortable = false;
            }
        } else {
            // Iterate through blocks
            for (let i = 0; i * k < N; i++) {
                const start = i * k;
                const end = start + k;

                // Blocks B (original) and S (target, sorted)
                const B = nums.slice(start, end);
                const S = sorted_nums.slice(start, end);

                // Step 3a: Multiset check (necessary condition)
                const sortedB = [...B].sort((a, b) => a - b);
                const sortedS = [...S].sort((a, b) => a - b);

                let multisetsMatch = true;
                for(let j=0; j<k; j++) {
                    if (sortedB[j] !== sortedS[j]) {
                        multisetsMatch = false;
                        break;
                    }
                }

                if (!multisetsMatch) {
                    isSortable = false;
                    break;
                }

                // Step 3b: Cyclic shift check
                // Since S is sorted, we check if B is a cyclic shift of S.
                let isCyclicShift = false;

                // Iterate over all k possible starting points j of S (the rotation amount)
                for (let j = 0; j < k; j++) {
                    let match = true;

                    // Check if B[t] == S[(j + t) % k] for all t
                    for (let t = 0; t < k; t++) {
                        if (B[t] !== S[(j + t) % k]) {
                            match = false;
                            break;
                        }
                    }

                    if (match) {
                        isCyclicShift = true;
                        break;
                    }
                }

                if (!isCyclicShift) {
                    isSortable = false;
                    break;
                }
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

